def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def validate_solution(nums, target, result):
    if result == (-1, -1):
        return True  # No solution case is valid
    left, right = result
    if left == right or left < 0 or right >= len(nums):
        return False  # Ensure indices are not reused and are valid
    return nums[left] + nums[right] == target

# Example usage
nums = [1, 2, 3, 4, 5]
target = 6
result = solve(nums, target)
assert validate_solution(nums, target, result), "Validation failed for the solution."
